_ = array2d < pow_expr  # type: ignore  # NotImplementedError: can only support '<=', '>=', or '=='
_ = array2d > pow_expr  # type: ignore  # NotImplementedError: can only support '<=', '>=', or '=='
_ = array2d != pow_expr  # type: ignore  # NotImplementedError: can only support '<=', '>=', or '=='
_ = array2d @ pow_expr  # type: ignore  # ValueError: 0-dimensional argument does not have enough dimensions for all core dimensions ('n', 'p')
_ = array2d % pow_expr  # type: ignore  # TypeError: unsupported operand type(s) for %: 'int' and 'pyscipopt.scip.PowExpr'

# Binary operators for array2d and var_expr

assert_type(array2d + var_expr, pyscipopt.scip.MatrixExpr)
assert_type(array2d - var_expr, pyscipopt.scip.MatrixExpr)
assert_type(array2d * var_expr, pyscipopt.scip.MatrixExpr)
assert_type(array2d / var_expr, pyscipopt.scip.MatrixExpr)
assert_type(array2d**var_expr, pyscipopt.scip.MatrixExpr)
assert_type(array2d <= var_expr, pyscipopt.scip.MatrixExprCons)
assert_type(array2d >= var_expr, pyscipopt.scip.MatrixExprCons)
assert_type(array2d == var_expr, pyscipopt.scip.MatrixExprCons)

_ = array2d < var_expr  # type: ignore  # NotImplementedError: can only support '<=', '>=', or '=='
_ = array2d > var_expr  # type: ignore  # NotImplementedError: can only support '<=', '>=', or '=='
_ = array2d != var_expr  # type: ignore  # NotImplementedError: can only support '<=', '>=', or '=='
_ = array2d @ var_expr  # type: ignore  # ValueError: 0-dimensional argument does not have enough dimensions for all core dimensions ('n', 'p')
_ = array2d % var_expr  # type: ignore  # TypeError: unsupported operand type(s) for %: 'int' and 'pyscipopt.scip.VarExpr'

# Binary operators for array2d and exprcons

_ = array2d + exprcons  # type: ignore  # TypeError: unsupported operand type(s) for +: 'int' and 'pyscipopt.scip.ExprCons'
_ = array2d - exprcons  # type: ignore  # TypeError: unsupported operand type(s) for -: 'int' and 'pyscipopt.scip.ExprCons'
_ = array2d * exprcons  # type: ignore  # TypeError: unsupported operand type(s) for *: 'int' and 'pyscipopt.scip.ExprCons'
_ = array2d / exprcons  # type: ignore  # TypeError: unsupported operand type(s) for /: 'int' and 'pyscipopt.scip.ExprCons'
_ = array2d**exprcons  # type: ignore  # TypeError: unsupported operand type(s) for ** or pow(): 'int' and 'pyscipopt.scip.ExprCons'
_ = array2d < exprcons  # type: ignore  # NotImplementedError: Ranged ExprCons can only support with '<=' or '>='.
_ = array2d <= exprcons  # type: ignore  # TypeError: Can't evaluate constraints as booleans.If you want to add a ranged constraint of the form   lhs <= expression <= rhsyou have to use parenthesis to break the Python syntax for chained comparisons:   lhs <= (expression <= rhs)
_ = array2d > exprcons  # type: ignore  # NotImplementedError: Ranged ExprCons can only support with '<=' or '>='.
_ = array2d >= exprcons  # type: ignore  # TypeError: ExprCons already has upper bound
_ = array2d == exprcons  # type: ignore  # NotImplementedError: Ranged ExprCons can only support with '<=' or '>='.
_ = array2d != exprcons  # type: ignore  # NotImplementedError: Ranged ExprCons can only support with '<=' or '>='.
_ = array2d @ exprcons  # type: ignore  # ValueError: matmul: Input operand 1 does not have enough dimensions (has 0, gufunc core with signature (n?,k),(k,m?)->(n?,m?) requires 1)
_ = array2d % exprcons  # type: ignore  # TypeError: unsupported operand type(s) for %: 'int' and 'pyscipopt.scip.ExprCons'

# Binary operators for array2d and matrixexprcons

_ = array2d + matrixexprcons  # type: ignore  # NotImplementedError: can only support '<=' or '>='
_ = array2d - matrixexprcons  # type: ignore  # NotImplementedError: can only support '<=' or '>='
_ = array2d * matrixexprcons  # type: ignore  # NotImplementedError: can only support '<=' or '>='
_ = array2d / matrixexprcons  # type: ignore  # NotImplementedError: can only support '<=' or '>='
_ = array2d**matrixexprcons  # type: ignore  # NotImplementedError: can only support '<=' or '>='
_ = array2d < matrixexprcons  # type: ignore  # NotImplementedError: can only support '<=' or '>='
_ = array2d <= matrixexprcons  # type: ignore  # ValueError: operands could not be broadcast together with shapes (3,) (2,2)
_ = array2d > matrixexprcons  # type: ignore  # NotImplementedError: can only support '<=' or '>='
_ = array2d >= matrixexprcons  # type: ignore  # ValueError: operands could not be broadcast together with shapes (3,) (2,2)
_ = array2d == matrixexprcons  # type: ignore  # NotImplementedError: can only support '<=' or '>='
_ = array2d != matrixexprcons  # type: ignore  # NotImplementedError: can only support '<=' or '>='
_ = array2d @ matrixexprcons  # type: ignore  # NotImplementedError: can only support '<=' or '>='
_ = array2d % matrixexprcons  # type: ignore  # NotImplementedError: can only support '<=' or '>='

